// DockerRunner unit tests with mocked execSync.
// Real Docker integration lives in tests/integration/docker-runner.integration.test.ts.

import { vi, describe, expect, afterEach } from "vitest";
import { Effect } from "effect";
import { existsSync, mkdtempSync, rmSync } from "node:fs";
import * as os from "node:os";
import * as path from "node:path";
import { itEffect, EITHER_LEFT, EITHER_RIGHT } from "./support/effect.js";

// createRequire keeps the vi.mock factory synchronous so the mocked module is
// ready before the dynamic imports below pull in the code under test.
const { childProcessActual } = vi.hoisted(() => {
  const { createRequire } = require("node:module") as typeof import("node:module");
  const req = createRequire(import.meta.url);
  return {
    childProcessActual: req("node:child_process") as typeof import("node:child_process"),
  };
});
vi.mock("node:child_process", () => ({ ...childProcessActual, execSync: vi.fn() }));

// Import after vi.mock so the module sees the mock.
const { DockerRunner } = await import("../src/runner/index.js");
const { ScenarioId, RUNTIME_KIND } = await import("../src/core/types.js");
const { ERROR_TAG, AGENT_START_CAUSE } = await import("../src/core/errors.js");
import * as childProcess from "node:child_process";

const execSyncMock = vi.mocked(childProcess.execSync);

const NONEXISTENT_IMAGE = "nonexistent:latest";
const HAPPY_CONTAINER_ID = "container-abc-123";

function makeScenario() {
  return {
    id: ScenarioId("docker-test"),
    name: "docker-test",
    description: "",
    setupPrompt: "noop",
    expectedBehavior: "",
    validationChecks: [] as string[],
  };
}

afterEach(() => {
  vi.resetAllMocks();
});

// ------------------------------------------------------------------
// DockerRunner.start() — failure paths
// ------------------------------------------------------------------

describe("DockerRunner.start()", () => {
  itEffect("returns AgentStartError{ImageMissing} when docker image inspect fails", function* () {
    execSyncMock.mockImplementation(() => {
      throw new Error("image not found");
    });
    const runner = new DockerRunner({ image: NONEXISTENT_IMAGE });
    const result = yield* Effect.either(runner.start(makeScenario()));
    expect(result._tag).toBe(EITHER_LEFT);
    if (result._tag === EITHER_LEFT) {
      expect(result.left._tag).toBe(ERROR_TAG.AgentStartError);
      expect(result.left.cause._tag).toBe(AGENT_START_CAUSE.ImageMissing);
      expect(
        (result.left.cause as { _tag: typeof AGENT_START_CAUSE.ImageMissing; image: string }).image,
      ).toBe(NONEXISTENT_IMAGE);
    }
  });

  itEffect("returns AgentStartError{ContainerStartFailed} when docker create fails", function* () {
    execSyncMock
      .mockReturnValueOnce(Buffer.from("")) // docker image inspect → image exists
      .mockImplementation(() => {
        throw new Error("docker create failed");
      }); // docker create → throws
    const runner = new DockerRunner({ image: "alpine:3.19" });
    const result = yield* Effect.either(runner.start(makeScenario()));
    expect(result._tag).toBe(EITHER_LEFT);
    if (result._tag === EITHER_LEFT) {
      expect(result.left._tag).toBe(ERROR_TAG.AgentStartError);
      expect(result.left.cause._tag).toBe(AGENT_START_CAUSE.ContainerStartFailed);
    }
  });

  itEffect("returns AgentHandle on happy path with correct kind and containerId", function* () {
    execSyncMock
      .mockReturnValueOnce(Buffer.from("")) // docker image inspect
      .mockReturnValueOnce(Buffer.from(`${HAPPY_CONTAINER_ID}\n`)) // docker create
      .mockReturnValueOnce(Buffer.from("")); // docker start
    const runner = new DockerRunner({ image: "alpine:3.19" });
    const result = yield* Effect.either(runner.start(makeScenario()));
    expect(result._tag).toBe(EITHER_RIGHT);
    if (result._tag === EITHER_RIGHT) {
      expect(result.right.kind).toBe(RUNTIME_KIND.Docker);
      expect(result.right.containerId).toBe(HAPPY_CONTAINER_ID);
      expect(existsSync(result.right.workspaceDir)).toBe(true);
      // Clean up the workspace dir manually (stop() would need real docker)
      rmSync(result.right.workspaceDir, { recursive: true, force: true });
    }
  });

  const CREATE_CALL_INDEX = 1;
  const createOptionCases: ReadonlyArray<
    readonly [string, Partial<ConstructorParameters<typeof DockerRunner>[0]>, string, string]
  > = [
    ["network: bridge", { network: "bridge" as const }, "--network", "bridge"],
    ["memoryMb: 512", { memoryMb: 512 }, "--memory", "512m"],
    ["cpus: 2", { cpus: 2 }, "--cpus", "2"],
  ];
  for (const [label, opts, expectedFlag, expectedValue] of createOptionCases) {
    itEffect(`passes ${label} option in docker create command`, function* () {
      execSyncMock
        .mockReturnValueOnce(Buffer.from(""))
        .mockReturnValueOnce(Buffer.from("cid\n"))
        .mockReturnValueOnce(Buffer.from(""));
      const runner = new DockerRunner({ image: "alpine:3.19", ...opts });
      yield* Effect.either(runner.start(makeScenario()));
      const createCall = execSyncMock.mock.calls[CREATE_CALL_INDEX]?.[0] as string | undefined;
      expect(createCall).toContain(expectedFlag);
      expect(createCall).toContain(expectedValue);
    });
  }
});

// ------------------------------------------------------------------
// DockerRunner.stop()
// ------------------------------------------------------------------

function makeFakeHandle(containerId?: string): Parameters<InstanceType<typeof DockerRunner>["stop"]>[0] {
  const dir = mkdtempSync(path.join(os.tmpdir(), "cc-judge-docker-test-"));
  return {
    __brand: "AgentHandle" as const,
    kind: RUNTIME_KIND.Docker,
    scenarioId: ScenarioId("docker-test"),
    workspaceDir: dir,
    containerId,
    initialFiles: new Map(),
    turnsExecuted: { count: 0 },
  };
}

describe("DockerRunner.stop()", () => {
  itEffect("removes workspace directory", function* () {
    execSyncMock.mockReturnValue(Buffer.from(""));
    const runner = new DockerRunner({ image: "alpine:3.19" });
    const handle = makeFakeHandle("some-container-id");
    const dir = handle.workspaceDir;
    expect(existsSync(dir)).toBe(true);
    yield* runner.stop(handle);
    expect(existsSync(dir)).toBe(false);
  });

  itEffect("calls docker kill and docker rm when containerId is present", function* () {
    execSyncMock.mockReturnValue(Buffer.from(""));
    const runner = new DockerRunner({ image: "alpine:3.19" });
    const handle = makeFakeHandle("cid-xyz");
    yield* runner.stop(handle);
    const calls = execSyncMock.mock.calls.map((c) => String(c[0]));
    expect(calls.some((c) => c.includes("docker kill") && c.includes("cid-xyz"))).toBe(true);
    expect(calls.some((c) => c.includes("docker rm") && c.includes("cid-xyz"))).toBe(true);
  });

  itEffect("skips docker calls when containerId is undefined", function* () {
    const runner = new DockerRunner({ image: "alpine:3.19" });
    const handle = makeFakeHandle(undefined);
    yield* runner.stop(handle);
    // No docker commands should be called
    expect(execSyncMock).not.toHaveBeenCalled();
  });

  itEffect("is idempotent — second stop() does not fail even when workspace is gone", function* () {
    execSyncMock.mockReturnValue(Buffer.from(""));
    const runner = new DockerRunner({ image: "alpine:3.19" });
    const handle = makeFakeHandle("cid-idem");
    yield* runner.stop(handle);
    // stop() invariant: idempotent — second call must not fail.
    yield* runner.stop(handle);
  });

  itEffect("succeeds even when docker kill throws (container already dead)", function* () {
    execSyncMock
      .mockImplementationOnce(() => {
        throw new Error("container already stopped");
      }) // docker kill throws
      .mockReturnValueOnce(Buffer.from("")); // docker rm succeeds
    const runner = new DockerRunner({ image: "alpine:3.19" });
    const handle = makeFakeHandle("cid-dead");
    // stop() invariant: never fails, even if docker kill throws.
    yield* runner.stop(handle);
  });
});

tests/property/schema-invariants.test.ts.source:
import { describe, it } from "vitest";
import * as fc from "fast-check";
import * as YAML from "yaml";
import { Value } from "@sinclair/typebox/value";
import {
  ScenarioYamlSchema,
  RunRecordSchema,
  WORKSPACE_PATH_PATTERN,
} from "../../src/core/schema.js";

// ── Arbitraries ────────────────────────────────────────────────────────────

const idArb = fc.stringMatching(/^[a-z][a-z0-9-]{0,40}$/);

// YAML round-trips cleanly for ASCII printable text that avoids YAML-special
// leading characters (|, >, {, [, etc.) and leading/trailing whitespace.
const safeStrArb = fc.stringMatching(/^[A-Za-z][A-Za-z0-9 _.,?!:;-]{0,50}$/);

const scenarioYamlArb = fc.record({
  id: idArb,
  name: safeStrArb,
  description: safeStrArb,
  setupPrompt: safeStrArb,
  expectedBehavior: safeStrArb,
  validationChecks: fc.array(safeStrArb, { minLength: 1, maxLength: 3 }),
});

const severityArb = fc.constantFrom(
  "minor" as const,
  "significant" as const,
  "critical" as const,
);

const issueArb = fc.record({
  issue: fc.string({ minLength: 1 }),
  severity: severityArb,
});

const runRecordArb = fc.record({
  source: fc.constantFrom("scenario" as const, "trace" as const),
  scenarioId: idArb,
  runNumber: fc.integer({ min: 1 }),
  modelName: fc.string(),
  judgeModel: fc.string(),
  startedAt: fc.string(),
  latencyMs: fc.integer({ min: 0 }),
  pass: fc.boolean(),
  reason: fc.string(),
  issues: fc.array(issueArb),
  overallSeverity: fc.oneof(severityArb, fc.constant(null)),
  judgeConfidence: fc.oneof(
    fc.nat(100).map((n) => n / 100),
    fc.constant(null),
  ),
  retryCount: fc.integer({ min: 0 }),
  toolCallCount: fc.integer({ min: 0 }),
  inputTokens: fc.integer({ min: 0 }),
  outputTokens: fc.integer({ min: 0 }),
  cacheReadTokens: fc.integer({ min: 0 }),
  cacheWriteTokens: fc.integer({ min: 0 }),
  transcriptPath: fc.string(),
  workspaceDiffSummary: fc.record({
    changed: fc.integer({ min: 0 }),
    added: fc.integer({ min: 0 }),
    removed: fc.integer({ min: 0 }),
  }),
});

const wppRegex = new RegExp(WORKSPACE_PATH_PATTERN);

// ── Helpers ─────────────────────────────────────────────────────────────────

function checkErrors(schema: Parameters<typeof Value.Errors>[0], value: unknown): string | null {
  const errs = [...Value.Errors(schema, value)].map((e) => `${e.path} ${e.message}`);
  return errs.length > 0 ? errs.join("; ") : null;
}

// ── Properties ─────────────────────────────────────────────────────────────

describe("property: schema invariants", () => {
  it("Property 1: ScenarioYamlSchema accepts arbitrary valid-shaped objects", () => {
    fc.assert(
      fc.property(scenarioYamlArb, (raw) => {
        const err = checkErrors(ScenarioYamlSchema, raw);
        if (err !== null) {
          throw new Error(
            `Valid-shaped scenario rejected by schema: ${err}\nInput: ${JSON.stringify(raw)}`,
          );
        }
      }),
      { numRuns: 200 },
    );
  });

  it("Property 2: ScenarioYamlSchema YAML round-trip preserves required fields", () => {
    fc.assert(
      fc.property(scenarioYamlArb, (raw) => {
        const yamlStr = YAML.stringify(raw);
        const reparsed: unknown = YAML.parse(yamlStr);
        const err = checkErrors(ScenarioYamlSchema, reparsed);
        if (err !== null) {
          throw new Error(`Round-tripped scenario rejected by schema: ${err}`);
        }
        const s = reparsed as typeof raw;
        if (
          s.id !== raw.id ||
          s.name !== raw.name ||
          s.setupPrompt !== raw.setupPrompt ||
          s.expectedBehavior !== raw.expectedBehavior
        ) {
          throw new Error(
            `Round-trip mutated required field(s):\n` +
              `  id: ${JSON.stringify(raw.id)} → ${JSON.stringify(s.id)}\n` +
              `  name: ${JSON.stringify(raw.name)} → ${JSON.stringify(s.name)}`,
          );
        }
      }),
      { numRuns: 100 },
    );
  });

  it("Property 3: RunRecord schema encodes non-negative numeric constraints (latencyMs, runNumber, tokens)", () => {
    fc.assert(
      fc.property(runRecordArb, (rec) => {
        if (checkErrors(RunRecordSchema, rec) !== null) return;
        if (rec.latencyMs < 0) throw new Error(`latencyMs=${rec.latencyMs} is negative`);
        if (rec.runNumber < 1) throw new Error(`runNumber=${rec.runNumber} < 1`);
        if (rec.retryCount < 0) throw new Error(`retryCount=${rec.retryCount} is negative`);
        if (rec.toolCallCount < 0) throw new Error(`toolCallCount=${rec.toolCallCount} is negative`);
        if (rec.inputTokens < 0) throw new Error(`inputTokens=${rec.inputTokens} is negative`);
        if (rec.outputTokens < 0) throw new Error(`outputTokens=${rec.outputTokens} is negative`);
        if (rec.cacheReadTokens < 0) throw new Error(`cacheReadTokens=${rec.cacheReadTokens} is negative`);
        if (rec.cacheWriteTokens < 0) throw new Error(`cacheWriteTokens=${rec.cacheWriteTokens} is negative`);
        if (rec.workspaceDiffSummary.changed < 0)
          throw new Error(`workspaceDiffSummary.changed=${rec.workspaceDiffSummary.changed} is negative`);
        if (rec.workspaceDiffSummary.added < 0)
          throw new Error(`workspaceDiffSummary.added=${rec.workspaceDiffSummary.added} is negative`);
        if (rec.workspaceDiffSummary.removed < 0)
          throw new Error(`workspaceDiffSummary.removed=${rec.workspaceDiffSummary.removed} is negative`);
      }),
      { numRuns: 200 },
    );
  });

  it("Property 4: RunRecord schema rejects negative latencyMs (timestamp ordering invariant)", () => {
    fc.assert(
      fc.property(runRecordArb, fc.integer({ min: -100_000, max: -1 }), (rec, badLatency) => {
        const invalid = { ...rec, latencyMs: badLatency };
        if (checkErrors(RunRecordSchema, invalid) === null) {
          throw new Error(`Schema accepted negative latencyMs=${badLatency}`);
        }
      }),
      { numRuns: 100 },
    );
  });

  it("Property 5: WORKSPACE_PATH_PATTERN — matching paths have no absolute prefix, no traversal, no backslash", () => {
    fc.assert(
      fc.property(fc.string(), (p) => {
        if (!wppRegex.test(p)) return;

        if (p.startsWith("/"))
          throw new Error(`Matched path has absolute unix prefix: ${JSON.stringify(p)}`);

        if (/^[A-Za-z]:/.test(p))
          throw new Error(`Matched path has Windows drive letter: ${JSON.stringify(p)}`);

        if (p.includes("\\"))
          throw new Error(`Matched path contains backslash: ${JSON.stringify(p)}`);

        if (/(^|\/)\.\.(?:\/|$)/.test(p))
          throw new Error(`Matched path contains traversal sequence: ${JSON.stringify(p)}`);
      }),
      { numRuns: 200 },
    );
  });
});

